// ── Component ─────────────────────────────────────────────────────────────────

export default function AgencePortal() {
  // Lire l'ID du client depuis l'URL (?id=xxx)
  const clientId = new URLSearchParams(window.location.search).get("id");

  const [openSection, setOpenSection] = useState("docs");
  const [uploads,     setUploads]     = useState({});
  const [formValues,  setFormValues]  = useState({});
  const [submitted,   setSubmitted]   = useState(false);
  const [dragOver,    setDragOver]    = useState(null);
  const [siretStatus, setSiretStatus] = useState(null);
  const [siretMsg,    setSiretMsg]    = useState("");
  const [siretConfirm, setSiretConfirm] = useState(null);
  const [loading,     setLoading]     = useState(true);
  const [notFound,    setNotFound]    = useState(false);

  // Charger le dossier client depuis Supabase
  useEffect(() => {
    const load = async () => {
      if (!clientId) { setNotFound(true); setLoading(false); return; }
      const data = await sbGet(clientId);
      if (!data) { setNotFound(true); setLoading(false); return; }
      
      if (data.informations) setFormValues(data.informations);
      if (data.documents)    setUploads(data.documents);
      setLoading(false);
    };
    load();
  }, [clientId]);

  // Sauvegarde automatique en temps réel (debounce 1s)
  const saveTimeout = useRef(null);
  const saveToSupabase = (newFormValues, newUploads) => {
    if (!clientId) return;
    clearTimeout(saveTimeout.current);
    saveTimeout.current = setTimeout(async () => {
      const allItems = SECTIONS.flatMap(s => s.items);
      const docs = {};
      const infos = {};
      allItems.forEach(item => {
        if (!item.type || item.type === "file") {
          docs[item.id] = !!newUploads[item.id];
        } else {
          infos[item.id] = newFormValues[item.id] || "";
        }
      });
      // Calculer le statut
      const totalDocs  = Object.values(docs).length;
      const totalInfos = Object.values(infos).filter(v => v).length;
      const totalFiles = Object.values(docs).filter(v => v).length;
      const total = totalDocs + Object.keys(infos).length;
      const done  = totalFiles + totalInfos;
      const status = done === 0 ? "pending" : done === total ? "complete" : "in_progress";
      await sbUpdate(clientId, { informations: infos, documents: docs, status });
    }, 1000);
  };

  const markUploaded = (id) => {
    setUploads((p) => {
      const next = { ...p, [id]: true };
      saveToSupabase(formValues, next);
      return next;
    });
  };
  const setField = (id, val) => {
    setFormValues((p) => {
      const next = { ...p, [id]: val };
      saveToSupabase(next, uploads);
      return next;
    });
  };


  const applyFetched = (fetched, nom, siret) => {
    setFormValues((prev) => ({
      ...prev,
      siret: siret || prev.siret,
      ...Object.fromEntries(Object.entries(fetched).filter(([, v]) => v)),
    }));
    setSiretStatus("success");
    setSiretMsg(`✓ ${nom} — informations récupérées automatiquement`);
    setSiretConfirm(null);
    setOpenSection("infos");
  };

  const getSectionProgress = (section) => {
    const done = section.items.filter((item) => {
      if (item.type && item.type !== "file") return !!formValues[item.id]?.trim();
      return !!uploads[item.id];
    }).length;
    return { done, total: section.items.length };
  };

  const totalDone  = SECTIONS.reduce((acc, s) => acc + getSectionProgress(s).done,  0);
  const totalItems = SECTIONS.reduce((acc, s) => acc + getSectionProgress(s).total, 0);
  const globalPct  = Math.round((totalDone / totalItems) * 100);
  const allDone    = totalDone === totalItems;

  if (loading) {
    return (
      <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'SF Pro Display',-apple-system,sans-serif" }}>
        <div style={{ textAlign: "center", color: "#86868b" }}>
          <div style={{ width: 32, height: 32, border: "3px solid #0071e3", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.8s linear infinite", margin: "0 auto 16px" }} />
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
          Chargement de votre dossier…
        </div>
      </div>
    );
  }

  if (notFound) {
    return (
      <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'SF Pro Display',-apple-system,sans-serif" }}>
        <div style={{ textAlign: "center", maxWidth: 400, padding: 32 }}>
          <img src={LOGO_GNI} alt="GNI" style={{ height: 60, objectFit: "contain", marginBottom: 24 }} />
          <h2 style={{ fontSize: 20, color: "#1d1d1f", marginBottom: 8 }}>Lien invalide</h2>
          <p style={{ color: "#86868b", fontSize: 14 }}>Ce lien de dossier n'existe pas ou a expiré. Contactez votre conseiller GNI.</p>
        </div>
      </div>
    );
  }

  if (submitted) {
    return (
      <div style={{ minHeight: "100vh", background: "linear-gradient(135deg,#f0fdf4,#ecfdf5)", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'SF Pro Display',-apple-system,sans-serif" }}>
        <div style={{ textAlign: "center", maxWidth: 480, padding: 40 }}>
          <div style={{ width: 80, height: 80, borderRadius: "50%", background: "linear-gradient(135deg,#34C759,#00c7be)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 24px", boxShadow: "0 8px 32px rgba(52,199,89,.3)" }}>
            <CheckCircle size={40} color="white" />
          </div>
          <h1 style={{ fontSize: 28, fontWeight: 800, color: "#1d1d1f", margin: "0 0 12px", letterSpacing: -.5 }}>Dossier transmis !</h1>
          <p style={{ fontSize: 15, color: "#86868b", lineHeight: 1.6, margin: "0 0 32px" }}>
            Votre dossier d'adhésion a bien été envoyé au Groupe National de l'Immobilier. 
            <strong style={{ color: "#1d1d1f" }}> {AGENCY.advisor}</strong> reviendra vers vous dans les meilleurs délais.
          </p>
          <div style={{ background: "white", borderRadius: 16, padding: 20, boxShadow: "0 2px 12px rgba(0,0,0,.06)", textAlign: "left" }}>
            <div style={{ fontSize: 12, fontWeight: 600, color: "#86868b", letterSpacing: .8, textTransform: "uppercase", marginBottom: 12 }}>Récapitulatif</div>
            {SECTIONS.map((s) => {
              const { done, total } = getSectionProgress(s);
              return (
                <div key={s.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderBottom: "1px solid #f5f5f7" }}>
                  <span style={{ fontSize: 13, color: "#1d1d1f" }}>{s.title}</span>
                  <span style={{ fontSize: 13, fontWeight: 700, color: done === total ? "#34C759" : "#FF9F0A" }}>{done}/{total}</span>
                </div>
              );
            })}
          </div>
          <p style={{ fontSize: 12, color: "#aeaeb2", marginTop: 20 }}>
            Une confirmation a été envoyée à votre adresse e-mail.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: "#f5f5f7", fontFamily: "'SF Pro Display',-apple-system,sans-serif" }}>

      {/* Header */}
      <div style={{ background: "white", borderBottom: "1px solid rgba(0,0,0,.06)", position: "sticky", top: 0, zIndex: 100, backdropFilter: "blur(20px)" }}>
        <div style={{ maxWidth: 720, margin: "0 auto", padding: "0 24px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 70 }}>
          <img src={LOGO_GNI} alt="Groupe National de l'Immobilier" style={{ height: 72, objectFit: "contain" }} />
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            {/* Call button */}
            <a href={`tel:${AGENCY.advisorPhone}`} style={{ display: "flex", alignItems: "center", gap: 8, background: "linear-gradient(135deg,#34C759,#30b350)", color: "white", textDecoration: "none", padding: "9px 16px", borderRadius: 22, boxShadow: "0 2px 10px rgba(52,199,89,.35)", transition: "opacity .2s" }}
              onMouseOver={e => e.currentTarget.style.opacity=".85"} onMouseOut={e => e.currentTarget.style.opacity="1"}>
              <Phone size={15} color="white" />
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: .3 }}>Appeler {AGENCY.advisor}</div>
                <div style={{ fontSize: 10, opacity: .9 }}>{AGENCY.advisorPhoneDisplay}</div>
              </div>
            </a>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "32px 24px 80px" }}>

        {/* Welcome banner */}
        <div style={{ background: "linear-gradient(135deg,#0071e3,#00c7be)", borderRadius: 20, padding: "28px 32px", marginBottom: 28, color: "white", position: "relative", overflow: "hidden" }}>
          <div style={{ position: "absolute", right: -20, top: -20, width: 140, height: 140, borderRadius: "50%", background: "rgba(255,255,255,.07)" }} />
          <div style={{ position: "absolute", right: 40, bottom: -40, width: 100, height: 100, borderRadius: "50%", background: "rgba(255,255,255,.05)" }} />
          <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", opacity: .8, marginBottom: 8 }}>Dossier d'adhésion</div>
          <h1 style={{ fontSize: 22, fontWeight: 800, margin: "0 0 4px", letterSpacing: -.3 }}>{AGENCY.name}</h1>
          <p style={{ fontSize: 13, opacity: .85, margin: "0 0 16px" }}>
            Votre conseiller dédié : <strong>{AGENCY.advisor}</strong> — <a href={`mailto:${AGENCY.advisorEmail}`} style={{ color: "white" }}>{AGENCY.advisorEmail}</a>
          </p>
          {/* Info pills */}
          <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, background: "rgba(255,255,255,.18)", borderRadius: 20, padding: "5px 12px", fontSize: 12, fontWeight: 600 }}>
              ⏱ Moins de 5 minutes à compléter
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 6, background: "rgba(255,255,255,.18)", borderRadius: 20, padding: "5px 12px", fontSize: 12, fontWeight: 600 }}>
              ✳︎ Tous les champs sont obligatoires
            </div>
          </div>
          {/* Progress */}
          <div style={{ background: "rgba(255,255,255,.2)", borderRadius: 10, height: 8, overflow: "hidden", marginBottom: 8 }}>
            <div style={{ width: `${globalPct}%`, height: "100%", background: "white", borderRadius: 10, transition: "width .5s ease" }} />
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, opacity: .9 }}>
            <span>{totalDone} éléments transmis sur {totalItems}</span>
            <strong>{globalPct}% complété</strong>
          </div>
        </div>

        {/* Info notice */}
        <div style={{ display: "flex", gap: 10, background: "#fffbeb", border: "1px solid #fde68a", borderRadius: 12, padding: "12px 16px", marginBottom: 24 }}>
          <AlertCircle size={16} color="#FF9F0A" style={{ flexShrink: 0, marginTop: 1 }} />
          <p style={{ fontSize: 13, color: "#92400e", margin: 0, lineHeight: 1.5 }}>
            Tous les documents marqués <strong>*</strong> sont obligatoires pour valider votre adhésion. Vous pouvez compléter ce formulaire en plusieurs fois — vos saisies sont conservées.
          </p>
        </div>

        {/* Sections */}
        {SECTIONS.map((section) => {
          const { done, total } = getSectionProgress(section);
          const isOpen   = openSection === section.id;
          const isFull   = done === total;

          return (
            <div key={section.id} style={{ background: "white", borderRadius: 20, marginBottom: 12, boxShadow: "0 2px 12px rgba(0,0,0,.05)", border: isFull ? `1.5px solid ${section.color}30` : "1.5px solid transparent", overflow: "hidden", transition: "all .3s" }}>

              {/* Section header */}
              <button onClick={() => setOpenSection(isOpen ? null : section.id)}
                style={{ width: "100%", display: "flex", alignItems: "center", gap: 14, padding: "20px 24px", background: "none", border: "none", cursor: "pointer", textAlign: "left" }}>
                {/* Progress ring visual */}
                <div style={{ width: 44, height: 44, borderRadius: 12, background: isFull ? section.color + "18" : "#f5f5f7", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, border: isFull ? `2px solid ${section.color}40` : "2px solid transparent", transition: "all .3s" }}>
                  {isFull
                    ? <CheckCircle size={20} color={section.color} />
                    : <span style={{ fontSize: 14, fontWeight: 800, color: section.color }}>{done}/{total}</span>
                  }
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ fontSize: 15, fontWeight: 700, color: "#1d1d1f" }}>{section.title}</span>
                    {isFull && (
                      <span style={{ fontSize: 10, fontWeight: 700, color: section.color, background: section.color + "14", padding: "2px 8px", borderRadius: 20, letterSpacing: .5, textTransform: "uppercase" }}>Complet</span>
                    )}
                  </div>
                  <div style={{ fontSize: 12, color: "#86868b", marginTop: 2 }}>{section.subtitle}</div>
                </div>
                {/* Mini progress bar */}
                <div style={{ width: 60, flexShrink: 0 }}>
                  <div style={{ height: 4, background: "#f2f2f7", borderRadius: 2, overflow: "hidden" }}>
                    <div style={{ width: `${(done / total) * 100}%`, height: "100%", background: isFull ? section.color : section.color + "80", borderRadius: 2, transition: "width .4s ease" }} />
                  </div>
                  <div style={{ fontSize: 10, color: "#86868b", marginTop: 3, textAlign: "right" }}>{Math.round((done / total) * 100)}%</div>
                </div>
                <ChevronDown size={16} color="#86868b" style={{ transform: isOpen ? "rotate(180deg)" : "none", transition: "transform .25s", flexShrink: 0 }} />
              </button>

              {/* Section body */}
              {isOpen && (
                <div style={{ padding: "0 24px 24px", borderTop: "1px solid #f5f5f7" }}>
                  <div style={{ height: 20 }} />
                  {section.items.map((item) => {
                    const isFile    = !item.type || item.type === "file";
                    const isDone    = isFile ? !!uploads[item.id] : !!formValues[item.id]?.trim();
                    const isDragging = dragOver === item.id;

                    return (
                      <div key={item.id} style={{ marginBottom: 16, background: isDone ? "#f9fffe" : "#fafafa", borderRadius: 14, border: `1.5px solid ${isDone ? section.color + "40" : "#e5e5ea"}`, padding: "16px 18px", transition: "all .2s" }}>
                        <div style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
                          {/* Status indicator */}
                          <div style={{ width: 28, height: 28, borderRadius: 8, background: isDone ? section.color + "18" : "#f0f0f5", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 2 }}>
                            {isDone
                              ? <CheckCircle size={16} color={section.color} />
                              : <item.Icon size={14} color="#86868b" />
                            }
                          </div>

                          <div style={{ flex: 1 }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8 }}>
                              <span style={{ fontSize: 13, fontWeight: 600, color: isDone ? "#1d1d1f" : "#1d1d1f" }}>{item.label}</span>
                              {item.required && <span style={{ fontSize: 10, color: "#FF3B30" }}>*</span>}
                              {isDone && <span style={{ fontSize: 10, color: section.color, fontWeight: 700, background: section.color + "14", padding: "1px 7px", borderRadius: 20 }}>✓ Reçu</span>}
                            </div>

                            {/* File upload */}
                            {isFile && !isDone && (
                              <div
                                onDragOver={(e) => { e.preventDefault(); setDragOver(item.id); }}
                                onDragLeave={() => setDragOver(null)}
                                onDrop={(e) => { e.preventDefault(); setDragOver(null); markUploaded(item.id); }}
                                style={{ border: `2px dashed ${isDragging ? section.color : "#d1d1d6"}`, borderRadius: 10, padding: "18px 16px", textAlign: "center", background: isDragging ? section.color + "06" : "white", transition: "all .2s", cursor: "pointer" }}
                                onClick={() => markUploaded(item.id)}>
                                <Upload size={18} color={isDragging ? section.color : "#86868b"} style={{ marginBottom: 6 }} />
                                <div style={{ fontSize: 12, color: isDragging ? section.color : "#86868b" }}>
                                  <strong>Cliquez pour déposer</strong> ou glissez votre fichier ici
                                </div>
                                <div style={{ fontSize: 11, color: "#aeaeb2", marginTop: 4 }}>PDF, JPG, PNG — max 10 Mo</div>
                              </div>
                            )}

                            {/* File uploaded state */}
                            {isFile && isDone && (
                              <div style={{ display: "flex", alignItems: "center", gap: 8, background: section.color + "0a", border: `1px solid ${section.color}20`, borderRadius: 8, padding: "8px 12px" }}>
                                <FileText size={14} color={section.color} />
                                <span style={{ fontSize: 12, color: section.color, fontWeight: 500, flex: 1 }}>document_transmis.pdf</span>
                                <button onClick={() => setUploads((p) => { const n = { ...p }; delete n[item.id]; return n; })}
                                  style={{ background: "none", border: "none", cursor: "pointer", color: "#86868b", display: "flex" }}>
                                  <X size={14} />
                                </button>
                              </div>
                            )}

                            {/* Text input */}
                            {item.type === "text" && item.id !== "siret" && (
                              <input value={formValues[item.id] || ""} onChange={(e) => setField(item.id, e.target.value)}
                                placeholder={item.placeholder}
                                style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: "1px solid #d1d1d6", fontSize: 13, outline: "none", boxSizing: "border-box", background: "white" }} />
                            )}

                            {/* SIRET smart lookup */}
                            {item.id === "siret" && (
                              <div>
                                <div style={{ position: "relative" }}>
                                  <input
                                    value={formValues.siret || ""}
                                    onChange={(e) => {
                                      const val = e.target.value;
                                      setField("siret", val);
                                      setSiretStatus(null);
                                      setSiretMsg("");
                                      setSiretConfirm(null);
                                    }}
                                    placeholder="Ex : 123 456 789 00012"
                                    maxLength={17}
                                    style={{ width: "100%", padding: "10px 44px 10px 12px", borderRadius: 10, border: `1px solid ${siretStatus === "error" ? "#FF3B30" : siretStatus === "success" ? "#34C759" : siretStatus === "confirm" ? "#FF9F0A" : "#d1d1d6"}`, fontSize: 13, outline: "none", boxSizing: "border-box", background: "white", fontFamily: "monospace" }}
                                  />
                                  <div style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)" }}>
                                    {siretStatus === "loading" && <div style={{ width: 16, height: 16, border: "2px solid #0071e3", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />}
                                    {siretStatus === "success" && <CheckCircle size={16} color="#34C759" />}
                                    {siretStatus === "error"   && <AlertCircle  size={16} color="#FF3B30" />}
                                    {siretStatus === "confirm" && <AlertCircle  size={16} color="#FF9F0A" />}
                                  </div>
                                </div>

                                {/* Confirmation box */}
                                {siretStatus === "confirm" && siretConfirm && (
                                  <div style={{ marginTop: 10, background: "#fffbeb", border: "1px solid #fde68a", borderRadius: 10, padding: "14px 16px" }}>
                                    <div style={{ fontSize: 13, fontWeight: 600, color: "#92400e", marginBottom: 4 }}>⚠️ Certains champs sont déjà remplis</div>
                                    <div style={{ fontSize: 12, color: "#78350f", marginBottom: 12 }}>
                                      Voulez-vous remplacer les champs existants par les données de <strong>{siretConfirm.nom}</strong> ?
                                    </div>
                                    <div style={{ display: "flex", gap: 8 }}>
                                      <button
                                        onClick={() => applyFetched(siretConfirm.fetched, siretConfirm.nom, formValues.siret)}
                                        style={{ flex: 1, padding: "8px 0", borderRadius: 8, border: "none", background: "#0071e3", color: "white", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>
                                        Oui, remplacer
                                      </button>
                                      <button
                                        onClick={() => { setSiretStatus(null); setSiretMsg(""); setSiretConfirm(null); }}
                                        style={{ flex: 1, padding: "8px 0", borderRadius: 8, border: "1px solid #d1d1d6", background: "white", color: "#3a3a3c", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>
                                        Non, conserver
                                      </button>
                                    </div>
                                  </div>
                                )}

                                {siretMsg && siretStatus !== "confirm" && (
                                  <div style={{ marginTop: 8, fontSize: 12, color: siretStatus === "success" ? "#34C759" : "#FF3B30" }}>
                                    {siretMsg}
                                  </div>
                                )}
                                {siretStatus === "success" && (
                                  <div style={{ marginTop: 8, background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#166534" }}>
                                    🎉 Les informations ont été pré-remplies dans la section <strong>Informations de l'agence</strong>. Vérifiez et complétez si besoin.
                                  </div>
                                )}
                                <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
                              </div>
                            )}
                            {item.type === "email" && (
                              <input type="email" value={formValues[item.id] || ""} onChange={(e) => setField(item.id, e.target.value)}
                                placeholder={item.placeholder}
                                style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: "1px solid #d1d1d6", fontSize: 13, outline: "none", boxSizing: "border-box", background: "white" }} />
                            )}
                            {item.type === "number" && (
                              <input type="number" value={formValues[item.id] || ""} onChange={(e) => setField(item.id, e.target.value)}
                                placeholder={item.placeholder} min="1"
                                style={{ width: 120, padding: "10px 12px", borderRadius: 10, border: "1px solid #d1d1d6", fontSize: 13, outline: "none", background: "white" }} />
                            )}
                            {item.type === "textarea" && (
                              <textarea value={formValues[item.id] || ""} onChange={(e) => setField(item.id, e.target.value)}
                                placeholder={item.placeholder} rows={3}
                                style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: "1px solid #d1d1d6", fontSize: 13, outline: "none", resize: "vertical", boxSizing: "border-box", fontFamily: "inherit", background: "white" }} />
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}

        {/* Submit */}
        <div style={{ background: "white", borderRadius: 20, padding: "24px 28px", boxShadow: "0 2px 16px rgba(0,0,0,.07)", marginTop: 8 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <div>
              <div style={{ fontSize: 15, fontWeight: 700, color: "#1d1d1f" }}>Soumettre votre dossier</div>
              <div style={{ fontSize: 12, color: "#86868b", marginTop: 2 }}>
                {allDone
                  ? "Votre dossier est complet — prêt à être transmis !"
                  : `Il manque encore ${totalItems - totalDone} élément${totalItems - totalDone > 1 ? "s" : ""} pour compléter votre dossier.`}
              </div>
            </div>
            <div style={{ fontSize: 22, fontWeight: 800, color: allDone ? "#34C759" : "#FF9F0A" }}>{globalPct}%</div>
          </div>

          {!allDone && (
            <div style={{ marginBottom: 16 }}>
              {SECTIONS.map((s) => {
                const { done, total } = getSectionProgress(s);
                if (done === total) return null;
                return (
                  <div key={s.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", fontSize: 12, color: "#86868b" }}>
                    <Circle size={6} color="#FF9F0A" fill="#FF9F0A" />
                    <span>{s.title} — {total - done} élément{total - done > 1 ? "s" : ""} manquant{total - done > 1 ? "s" : ""}</span>
                  </div>
                );
              })}
            </div>
          )}

          <button onClick={async () => {
            try {
              await sbUpdate(clientId, {
                status: allDone ? "complete" : "in_progress",
                informations: formValues,
                documents: uploads,
              });
            } catch(e) { console.error(e); }
            setSubmitted(true);
          }}
            style={{ width: "100%", padding: "14px 0", borderRadius: 12, border: "none", background: allDone ? "linear-gradient(135deg,#34C759,#00c7be)" : "linear-gradient(135deg,#0071e3,#00c7be)", color: "white", fontSize: 15, fontWeight: 700, cursor: "pointer", boxShadow: allDone ? "0 4px 16px rgba(52,199,89,.35)" : "0 4px 16px rgba(0,113,227,.35)", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, transition: "all .3s" }}>
            {allDone ? <CheckCircle size={18} /> : <ChevronRight size={18} />}
            {allDone ? "Transmettre mon dossier complet" : "Transmettre mon dossier (incomplet)"}
          </button>

          {!allDone && (
            <p style={{ fontSize: 11, color: "#aeaeb2", textAlign: "center", marginTop: 10, marginBottom: 0 }}>
              Vous pouvez soumettre un dossier incomplet — votre conseiller vous relancera pour les éléments manquants.
            </p>
          )}
        </div>

        {/* Footer */}
        <div style={{ textAlign: "center", marginTop: 32, fontSize: 12, color: "#aeaeb2" }}>
          <div style={{ marginBottom: 4 }}>Groupe National de l'Immobilier — Espace adhésion sécurisé</div>
          <div>Des questions ? Contactez <a href={`mailto:${AGENCY.advisorEmail}`} style={{ color: "#0071e3" }}>{AGENCY.advisorEmail}</a></div>
        </div>
      </div>
    </div>
  );
}
// update
